import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quoting: main items
  it.todo("returns empty results for empty steps");
  it.todo("quotes a single sword for a new customer (base premium + 5G fee)");
  it.todo("quotes a single amulet at its base premium");
  it.todo("quotes a single staff at its base premium");
  it.todo("quotes a single potion at its base premium");

  // Quoting: components
  it.todo("quotes a single component (e.g. rune) at 25G base premium");
  it.todo("quotes a building block of 3 alike components at the special 60G base premium");

  // Quoting: surcharges
  it.todo("applies a 50% risk surcharge to cursed items");
  it.todo("applies a 30% risk surcharge to highly enchanted items (level >= 5)");

  // Quoting: customer-level adjustments
  it.todo("applies a 20% loyalty discount for customers with >= 2 years of business");
  it.todo("applies a 10% initial assessment surcharge on the customer's first insurance");
  it.todo("applies a 15% discount on each contract after the first");

  // Quoting: rounding and fee
  it.todo("rounds the final premium up to whole G (in MHPCO's favor) and adds the 5G processing fee");

  // Claims
  it.todo("processes a claim with a 100G deductible per damage event");
  it.todo("caps total payout per policy at twice the insurance sum");
  it.todo("reimburses damage to items with enchantment >= 8 at 50% of the damage amount");
  it.todo("fully reimburses damage to items made of dragon material");
});

