export type Customer = {
  yearsWithMHPCO: number;
};

export type Step = Record<string, unknown> & { op: string };

export type Scenario = {
  customer: Customer;
  steps: Step[];
};

export type StepResult = Record<string, number>;

export type ScenarioResult = {
  results: StepResult[];
};

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_SURCHARGE = 0.10;
const PROCESSING_FEE = 5;

// Rounds up to whole G in MHPCO's favor, guarding against floating-point drift.
const roundUpInFavor = (amount: number): number =>
  Math.ceil(amount - 1e-9);

type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

const processStep = (step: Step, _customer: Customer): StepResult => {
  const items = step.items as Item[];
  const base = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const premium = roundUpInFavor(base * (1 + FIRST_INSURANCE_SURCHARGE)) + PROCESSING_FEE;
  return { premium };
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => processStep(step, scenario.customer));
  return { results };
};

